def create_saml_response(user_email, user_attributes, sp_entity_id, acs_url, in_response_to=None):
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_before = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_on_or_after = (datetime.utcnow() + timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    session_not_on_or_after = (datetime.utcnow() + timedelta(hours=8)).strftime('%Y-%m-%dT%H:%M:%SZ')
    
    response_id = '_' + str(uuid.uuid4())
    assertion_id = '_' + str(uuid.uuid4())
    
    attribute_statement = ''
    for attr_name, attr_value in user_attributes.items():
        attribute_statement += f'''
        <saml:Attribute Name="{attr_name}" NameFormat="urn:oasis:names:tc:SAML:2.0:attrname-format:basic">
            <saml:AttributeValue xmlns:xs="http://www.w3.org/2001/XMLSchema" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xsi:type="xs:string">{attr_value}</saml:AttributeValue>
        </saml:Attribute>'''
    
    in_response_to_attr = f'InResponseTo="{in_response_to}"' if in_response_to else ''
    
    assertion = f'''<saml:Assertion xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" ID="{assertion_id}" IssueInstant="{issue_instant}" Version="2.0">
        <saml:Issuer>https://idp.internal.com</saml:Issuer>
        <saml:Subject>
            <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{user_email}</saml:NameID>
            <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
                <saml:SubjectConfirmationData {in_response_to_attr} NotOnOrAfter="{not_on_or_after}" Recipient="{acs_url}"/>
            </saml:SubjectConfirmation>
        </saml:Subject>
        <saml:Conditions NotBefore="{not_before}" NotOnOrAfter="{not_on_or_after}">
            <saml:AudienceRestriction>
                <saml:Audience>{sp_entity_id}</saml:Audience>
            </saml:AudienceRestriction>
        </saml:Conditions>
        <saml:AuthnStatement AuthnInstant="{issue_instant}" SessionNotOnOrAfter="{session_not_on_or_after}">
            <saml:AuthnContext>
                <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
            </saml:AuthnContext>
        </saml:AuthnStatement>
        <saml:AttributeStatement>{attribute_statement}
        </saml:AttributeStatement>
    </saml:Assertion>'''
    
    assertion_element = etree.fromstring(assertion.encode('utf-8'))
    
    with open(PRIVATE_KEY_PATH, 'rb') as f:
        private_key_data = f.read()
    
    with open(CERT_PATH, 'rb') as f:
        cert_data = f.read()
    
    signer = XMLSigner(
        method=signxml.methods.enveloped,
        signature_algorithm='rsa-sha256',
        digest_algorithm='sha256',
        c14n_algorithm='http://www.w3.org/2001/10/xml-exc-c14n#'
    )
    
    signed_assertion = signer.sign(assertion_element, key=private_key_data, cert=cert_data)
    signed_assertion_str = etree.tostring(signed_assertion, encoding='unicode')
    
    saml_response = f'''<samlp:Response xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" Destination="{acs_url}" ID="{response_id}" {in_response_to_attr} IssueInstant="{issue_instant}" Version="2.0">
        <saml:Issuer>https://idp.internal.com</saml:Issuer>
        <samlp:Status>
            <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
        </samlp:Status>
        {signed_assertion_str}
    </samlp:Response>'''
    
    return base64.b64encode(saml_response.encode('utf-8')).decode('utf-8')

