@app.route('/sso', methods=['GET', 'POST'])
def sso():
    if request.method == 'GET':
        saml_request = request.args.get('SAMLRequest', '')
        relay_state = request.args.get('RelayState', '')
        
        return render_template_string(LOGIN_FORM, saml_request=saml_request, relay_state=relay_state, error=None)
    
    elif request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        saml_request = request.form.get('SAMLRequest', '')
        relay_state = request.form.get('RelayState', '')
        
        if username in USERS_DB and USERS_DB[username]['password'] == password:
            user_attributes = USERS_DB[username]['attributes']
            
            sp_entity_id = 'https://sp.example.com'
            acs_url = 'https://sp.example.com/saml/acs'
            in_response_to = None
            
            if saml_request:
                try:
                    decoded_request = base64.b64decode(saml_request)
                    import zlib
                    inflated_request = zlib.decompress(decoded_request, -15)
                    request_xml = etree.fromstring(inflated_request)
                    
                    in_response_to = request_xml.get('ID')
                    acs_url_from_request = request_xml.get('AssertionConsumerServiceURL')
                    if acs_url_from_request:
                        acs_url = acs_url_from_request
                    
                    issuer = request_xml.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Issuer')
                    if issuer is not None:
                        sp_entity_id = issuer.text
                except Exception as e:
                    pass
            
            saml_response = create_saml_response(
                username, 
                user_attributes, 
                sp_entity_id, 
                acs_url,
                in_response_to
            )
            
            return render_template_string(POST_FORM, saml_response=saml_response, acs_url=acs_url, relay_state=relay_state)
        else:
            return render_template_string(LOGIN_FORM, saml_request=saml_request, relay_state=relay_state, error='Invalid credentials')

